import{_ as e,o as a,c as s,Q as l}from"./chunks/framework.b6910bb2.js";const t="/vitePress-blob/assets/34.d969c1b7.png",o="/vitePress-blob/assets/35.54c57f35.png",i="/vitePress-blob/assets/36.b44a4fc8.png",n="/vitePress-blob/assets/40.cce6d672.png",p="/vitePress-blob/assets/38.f0391b64.png",r="/vitePress-blob/assets/37.3c94d79d.png",P=JSON.parse('{"title":"【AI 实践】 AI 时代下重构旧时代系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai/【AI 实践】 AI 时代下重构旧时代系统.md","filePath":"guide/ai/【AI 实践】 AI 时代下重构旧时代系统.md","lastUpdated":1778295645000}'),c={name:"guide/ai/【AI 实践】 AI 时代下重构旧时代系统.md"},d=l('<h1 id="【ai-实践】-ai-时代下重构旧时代系统" tabindex="-1">【AI 实践】 AI 时代下重构旧时代系统 <a class="header-anchor" href="#【ai-实践】-ai-时代下重构旧时代系统" aria-label="Permalink to &quot;【AI 实践】 AI 时代下重构旧时代系统&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>软件工程本质是一个对抗熵增的过程，我们需要将 无序的需求 转化成 有序的代码。</p><p><img src="'+t+'" alt="image.png"></p><p>随着 AI 编程的普及，AI 是一个高增益放大器，必须匹配更强的阻尼机制（例如严格的测试、Review、Linting、架构设计）。</p><p>如何让 AI 在面对无序的需求时，生成有序代码是一个值得思考的问题。</p><p>接下来，在下将以 重构旧时代系统 为例，去思考在 AI 时代下，我们应该如何去构建一个系统，来对抗熵增，让系统保持有序。</p><h2 id="核心理念1-规则约束" tabindex="-1">核心理念1: 规则约束 <a class="header-anchor" href="#核心理念1-规则约束" aria-label="Permalink to &quot;核心理念1: 规则约束&quot;">​</a></h2><h3 id="为什么需要规则约束" tabindex="-1">为什么需要规则约束 <a class="header-anchor" href="#为什么需要规则约束" aria-label="Permalink to &quot;为什么需要规则约束&quot;">​</a></h3><p>AI 模型具备&quot;通识能力&quot;，给它一个需求描述，它确实能生成可运行的代码。</p><p>但问题在于，这些代码往往是&quot;外星代码&quot;：</p><ul><li>风格不一致（命名规范、目录结构、分层方式与项目现有代码不同）</li><li>复用率低（没有利用项目已有的公共组件、工具函数、请求封装、生成的代码像一坨 &quot;💩山&quot;）</li><li>采纳率低（Code Review 时研发同学看到&quot;外来风格&quot;的代码，会产生大量修改意见）</li></ul><p>结果就是：AI 生成了代码，但 Review 成本和返工成本反而更高了。</p><p>这时候可能有同学会说: &quot;是用的 AI 模型太垃圾啦，换一个牛一点的模型就好了！&quot;，诚然，模型的能力是一个重要因素，但除了模型能力之外，<strong>规则约束</strong>也是一个重要因素。</p><p>规则约束可以给 AI 一个已有的实现作为参照，限定 AI 的能力边界，让它照着复刻一份，而不是凭空创造，这就像给一个新入职的工程师说&quot;你照着这个模块的风格，写一个类似的&quot;，而不是&quot;你自由发挥&quot;——前者往往能更快产出符合团队规范的代码。</p><h3 id="【实践】规则约束" tabindex="-1">【实践】规则约束 <a class="header-anchor" href="#【实践】规则约束" aria-label="Permalink to &quot;【实践】规则约束&quot;">​</a></h3><p>在这次 AI 重构系统的实践中，在下给系统划分了 4 层规则约束 （架构层、示范层、视觉层、约束层）</p><ul><li>架构层：定义系统的分层架构，明确每一层的职责和边界，让 AI 「对系统有一个整体的认知」</li><li>示范层：提供已有的实现作为示范，Good Case 与 Bad Case，告诉 AI「标准产出长什么样」</li><li>视觉层：提供系统的目录结构、文件结构等视觉信息，告诉 AI「页面应该长什么样」</li><li>约束层：提供一些具体的规则约束，例如命名规范、函数长度、注释规范等，告诉 AI「禁止什么、必须怎样」</li></ul><p><img src="'+o+'" alt="image.png"></p><p><img src="'+i+`" alt="image.png"></p><h4 id="架构层" tabindex="-1">架构层 <a class="header-anchor" href="#架构层" aria-label="Permalink to &quot;架构层&quot;">​</a></h4><p>在架构层面，我们定义了系统的分层架构，明确了每一层的职责和边界，让 AI 对系统有一个整体的认知。例如在这次重构事件中，划分了 3 层：</p><ul><li>Model 层：负责数据模型的定义和数据访问</li><li>ViewModel 层：负责业务逻辑的处理和数据的转换</li><li>View 层：负责 UI 的展示和用户交互</li></ul><p>通过明确的分层架构，AI 在生成代码时就有了清晰的职责划分，知道每一层应该做什么，从而生成符合架构规范的代码，同时也方便了后续的复用。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">API 层 (client/src/api/)               → 定义 MethodsAPI 常量 + callAPI 调用函数</span></span>
<span class="line"><span style="color:#e1e4e8;">Model 层 (client/src/models/)           → MobX 业务状态模型（makeAutoObservable 单例）</span></span>
<span class="line"><span style="color:#e1e4e8;">ViewModel 层 (client/src/view-models/)  → 页面级 UI 交互逻辑 (可选)</span></span>
<span class="line"><span style="color:#e1e4e8;">View 层 (client/src/pages/)             → React 组件（observer + memo）</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">API 层 (client/src/api/)               → 定义 MethodsAPI 常量 + callAPI 调用函数</span></span>
<span class="line"><span style="color:#24292e;">Model 层 (client/src/models/)           → MobX 业务状态模型（makeAutoObservable 单例）</span></span>
<span class="line"><span style="color:#24292e;">ViewModel 层 (client/src/view-models/)  → 页面级 UI 交互逻辑 (可选)</span></span>
<span class="line"><span style="color:#24292e;">View 层 (client/src/pages/)             → React 组件（observer + memo）</span></span></code></pre></div><blockquote><p>实践中，Model 层尽量保持单一职责，如有数据聚合、数据转化等诉求，优先放在 ViewModel 层去实现，避免 Model 层过于臃肿，AI 也可以尽可能的复用 Model 层的代码，减少重复代码的生成。</p></blockquote><h4 id="示范层" tabindex="-1">示范层 <a class="header-anchor" href="#示范层" aria-label="Permalink to &quot;示范层&quot;">​</a></h4><p>在这次实践中，在下从 组件编写规范、组件复用规范、API 接口设计规范、项目整体结构 维度提供了一个已有的实现作为示范，告诉 AI「标准产出长什么样」，同时也提供了一些 Bad Case，告诉 AI「不符合规范的产出长什么样」，让 AI 知道什么是好的代码，什么是不好的代码，从而提高生成代码的质量和采纳率。</p><h4 id="视觉层" tabindex="-1">视觉层 <a class="header-anchor" href="#视觉层" aria-label="Permalink to &quot;视觉层&quot;">​</a></h4><p>在视觉层面，在下提供设计系统（主题色、UI库、图标、字体等）、布局系统（Grid 布局、Flex 布局等）、样式开发规范、响应策略等视觉信息，告诉 AI「页面应该长什么样」</p><p><img src="`+n+'" alt="image.png"></p><h4 id="约束层" tabindex="-1">约束层 <a class="header-anchor" href="#约束层" aria-label="Permalink to &quot;约束层&quot;">​</a></h4><p>在约束层面，在下提供了一些具体的规则约束，例如命名规范、函数长度、注释规范等，告诉 AI「禁止什么、必须怎样」，让 AI 在生成代码时有明确的规则可遵循，从而提高代码的质量和一致性。</p><p>生成效果如下：</p><p><img src="'+p+'" alt="image.png"></p><h2 id="收益" tabindex="-1">收益 <a class="header-anchor" href="#收益" aria-label="Permalink to &quot;收益&quot;">​</a></h2><p><img src="'+r+'" alt="image.png"></p>',37),h=[d];function u(_,I,b,A,m,g){return a(),s("div",null,h)}const v=e(c,[["render",u]]);export{P as __pageData,v as default};
